 1	import type { ReactNode } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { DropdownItem } from '@patternfly/react-core';
 5	
 6	/**
 7	 * `DropdownItemLink` is a functional component that renders a dropdown item with a link.
 8	 *
 9	 * @param {Object} props - The properties passed to the component.
10	 * @param {string} props.itemKey - The DropdownItem key.
11	 * @param {string} props.href - The URL to navigate to when the dropdown item is clicked.
12	 * @param {string} props.description - The description to display below the dropdown item.
13	 *
14	 * @returns {ReactElement} The rendered JSX element.
15	 */
16	export const DropdownItemLink = ({
17	  children,
18	  description,
19	  href = '#',
20	  itemKey,
21	  value,
22	}: DropdownItemLinkProps) => {
23	  return (
24	    <DropdownItem key={itemKey} value={value}>
25	      <Link to={href} className="pf-c-dropdown__menu-item pf-m-description">
26	        <div className="pf-c-menu__list-item--Displays">{children}</div>
27	        {description && <div className="pf-c-dropdown__menu-item-description">{description}</div>}
28	      </Link>
29	    </DropdownItem>
30	  );
31	};
32	
33	type DropdownItemLinkProps = {
34	  itemKey: string;
35	  value: number;
36	  href: string;
37	  description?: string;
38	  children?: ReactNode;
39	};

