 1	import { DropdownItemLink } from 'src/components/actions/DropdownItemLink';
 2	import { DeleteModal } from 'src/modules/Providers/modals/DeleteModal/DeleteModal';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { StorageMapModel, StorageMapModelRef } from '@kubev2v/types';
 8	import { DropdownItem } from '@patternfly/react-core';
 9	
10	import type { StorageMapData } from '../utils/types/StorageMapData';
11	
12	export const StorageMapActionsDropdownItems = ({ data }: StorageMapActionsDropdownItemsProps) => {
13	  const { t } = useForkliftTranslation();
14	  const { showModal } = useModal();
15	
16	  const { obj: StorageMap } = data;
17	
18	  const StorageMapURL = getResourceUrl({
19	    name: StorageMap?.metadata?.name,
20	    namespace: StorageMap?.metadata?.namespace,
21	    reference: StorageMapModelRef,
22	  });
23	
24	  const onClick = () => {
25	    showModal(<DeleteModal resource={StorageMap!} model={StorageMapModel} />);
26	  };
27	
28	  return [
29	    <DropdownItemLink
30	      value={0}
31	      itemKey="EditStorageMapping"
32	      href={StorageMapURL}
33	      description={t('Edit storage map')}
34	    />,
35	
36	    <DropdownItem
37	      value={1}
38	      key="delete"
39	      isDisabled={!data?.permissions?.canDelete}
40	      onClick={onClick}
41	    >
42	      {t('Delete storage map')}
43	    </DropdownItem>,
44	  ];
45	};
46	
47	type StorageMapActionsDropdownItemsProps = {
48	  data: StorageMapData;
49	};

